import { Subscription } from "./subscription";

export interface SubscriptionRepository {
  save(subscription: Subscription): void;
  findById(id: string): Subscription | null;
  findByUserId(userId: string): Subscription[];
}

/**
 * In-memory implementation of SubscriptionRepository.
 * Intended for use in tests and local development only.
 */
export class InMemorySubscriptionRepository implements SubscriptionRepository {
  private readonly store = new Map<string, Subscription>();

  save(subscription: Subscription): void {
    this.store.set(subscription.id, { ...subscription });
  }

  findById(id: string): Subscription | null {
    return this.store.get(id) ?? null;
  }

  findByUserId(userId: string): Subscription[] {
    return Array.from(this.store.values()).filter(
      (s) => s.userId === userId
    );
  }
}

