import { AppError } from "../shared/app-error";
import { InMemorySubscriptionRepository } from "./subscription-repository";
import { SubscriptionService } from "./subscription-service";

// ─── helpers ────────────────────────────────────────────────────────────────

function makeService() {
  const repo = new InMemorySubscriptionRepository();
  const service = new SubscriptionService(repo);
  return { repo, service };
}

const THIRTY_DAYS_MS = 2_592_000_000;

// ─── AC1: createSubscription ─────────────────────────────────────────────────

describe("createSubscription", () => {
  it("AC1: creates a subscription with status 'active' for given userId and planId", () => {
    const { service } = makeService();
    const before = Date.now();
    const sub = service.createSubscription("user-1", "plan-basic");
    const after = Date.now();

    expect(sub.userId).toBe("user-1");
    expect(sub.planId).toBe("plan-basic");
    expect(sub.status).toBe("active");
    expect(sub.id).toBeTruthy();
    expect(sub.createdAt).toBeGreaterThanOrEqual(before);
    expect(sub.createdAt).toBeLessThanOrEqual(after);
  });

  it("AC1: persists the subscription so it can be retrieved", () => {
    const { service } = makeService();
    const sub = service.createSubscription("user-1", "plan-pro");
    const fetched = service.getSubscription(sub.id);
    expect(fetched).toEqual(sub);
  });

  it("AC1: sets renewalDate to approximately now + 30 days", () => {
    const { service } = makeService();
    const before = Date.now();
    const sub = service.createSubscription("user-1", "plan-basic");
    const after = Date.now();

    expect(sub.renewalDate).toBeGreaterThanOrEqual(before + THIRTY_DAYS_MS);
    expect(sub.renewalDate).toBeLessThanOrEqual(after + THIRTY_DAYS_MS);
  });
});

// ─── AC2 & AC3: getSubscription ──────────────────────────────────────────────

describe("getSubscription", () => {
  it("AC2: returns the subscription when it exists", () => {
    const { service } = makeService();
    const sub = service.createSubscription("user-2", "plan-basic");
    const result = service.getSubscription(sub.id);
    expect(result).toEqual(sub);
  });

  it("AC3: throws SUBSCRIPTION_NOT_FOUND when subscription does not exist", () => {
    const { service } = makeService();
    expect(() => service.getSubscription("does-not-exist")).toThrow(AppError);
    try {
      service.getSubscription("does-not-exist");
    } catch (err) {
      expect((err as AppError).code).toBe("SUBSCRIPTION_NOT_FOUND");
    }
  });
});

// ─── AC4 & AC5: cancelSubscription ───────────────────────────────────────────

describe("cancelSubscription", () => {
  it("AC4: changes status to 'cancelled' and sets cancellationDate", () => {
    const { service } = makeService();
    const sub = service.createSubscription("user-3", "plan-basic");
    const before = Date.now();
    const cancelled = service.cancelSubscription(sub.id);
    const after = Date.now();

    expect(cancelled.status).toBe("cancelled");
    expect(cancelled.cancellationDate).toBeGreaterThanOrEqual(before);
    expect(cancelled.cancellationDate).toBeLessThanOrEqual(after);
  });

  it("AC4: persisted subscription reflects cancelled status", () => {
    const { service } = makeService();
    const sub = service.createSubscription("user-3", "plan-basic");
    service.cancelSubscription(sub.id);
    const fetched = service.getSubscription(sub.id);
    expect(fetched.status).toBe("cancelled");
    expect(fetched.cancellationDate).toBeDefined();
  });

  it("AC5: throws SUBSCRIPTION_ALREADY_CANCELLED when cancelling a cancelled subscription", () => {
    const { service } = makeService();
    const sub = service.createSubscription("user-3", "plan-basic");
    service.cancelSubscription(sub.id);

    expect(() => service.cancelSubscription(sub.id)).toThrow(AppError);
    try {
      service.cancelSubscription(sub.id);
    } catch (err) {
      expect((err as AppError).code).toBe("SUBSCRIPTION_ALREADY_CANCELLED");
    }
  });

  it("AC3 (via cancel): throws SUBSCRIPTION_NOT_FOUND for unknown id", () => {
    const { service } = makeService();
    expect(() => service.cancelSubscription("ghost-id")).toThrow(AppError);
    try {
      service.cancelSubscription("ghost-id");
    } catch (err) {
      expect((err as AppError).code).toBe("SUBSCRIPTION_NOT_FOUND");
    }
  });
});

// ─── AC6 & AC7: renewSubscription ────────────────────────────────────────────

describe("renewSubscription", () => {
  it("AC6: updates renewalDate to now + 30 days for an active subscription", () => {
    const { service } = makeService();
    const sub = service.createSubscription("user-4", "plan-basic");
    const before = Date.now();
    const renewed = service.renewSubscription(sub.id);
    const after = Date.now();

    expect(renewed.renewalDate).toBeGreaterThanOrEqual(before + THIRTY_DAYS_MS);
    expect(renewed.renewalDate).toBeLessThanOrEqual(after + THIRTY_DAYS_MS);
  });

  it("AC6: renew persists the updated renewalDate", () => {
    const { service } = makeService();
    const sub = service.createSubscription("user-4", "plan-basic");
    const renewed = service.renewSubscription(sub.id);
    const fetched = service.getSubscription(sub.id);
    expect(fetched.renewalDate).toBe(renewed.renewalDate);
  });

  it("AC6: renew does not change status — stays 'active'", () => {
    const { service } = makeService();
    const sub = service.createSubscription("user-4", "plan-basic");
    const renewed = service.renewSubscription(sub.id);
    expect(renewed.status).toBe("active");
  });

  it("AC7: throws CANNOT_RENEW_CANCELLED for a cancelled subscription", () => {
    const { service } = makeService();
    const sub = service.createSubscription("user-4", "plan-basic");
    service.cancelSubscription(sub.id);

    expect(() => service.renewSubscription(sub.id)).toThrow(AppError);
    try {
      service.renewSubscription(sub.id);
    } catch (err) {
      expect((err as AppError).code).toBe("CANNOT_RENEW_CANCELLED");
    }
  });

  it("AC3 (via renew): throws SUBSCRIPTION_NOT_FOUND for unknown id", () => {
    const { service } = makeService();
    expect(() => service.renewSubscription("ghost-id")).toThrow(AppError);
    try {
      service.renewSubscription("ghost-id");
    } catch (err) {
      expect((err as AppError).code).toBe("SUBSCRIPTION_NOT_FOUND");
    }
  });
});

// ─── AC8: listSubscriptions ───────────────────────────────────────────────────

describe("listSubscriptions", () => {
  it("AC8: returns all subscriptions (active and cancelled) for a user", () => {
    const { service } = makeService();
    const sub1 = service.createSubscription("user-5", "plan-basic");
    const sub2 = service.createSubscription("user-5", "plan-pro");
    service.cancelSubscription(sub2.id);

    const list = service.listSubscriptions("user-5");
    expect(list).toHaveLength(2);
    const ids = list.map((s) => s.id);
    expect(ids).toContain(sub1.id);
    expect(ids).toContain(sub2.id);
  });

  it("AC8: returns empty array when user has no subscriptions", () => {
    const { service } = makeService();
    expect(service.listSubscriptions("user-unknown")).toEqual([]);
  });

  it("AC8: does not return subscriptions belonging to a different user", () => {
    const { service } = makeService();
    service.createSubscription("user-A", "plan-basic");
    service.createSubscription("user-B", "plan-basic");

    const listA = service.listSubscriptions("user-A");
    expect(listA).toHaveLength(1);
    expect(listA[0].userId).toBe("user-A");
  });

  it("AC8: reflects latest status after cancellation", () => {
    const { service } = makeService();
    const sub = service.createSubscription("user-5", "plan-basic");
    service.cancelSubscription(sub.id);

    const list = service.listSubscriptions("user-5");
    const found = list.find((s) => s.id === sub.id);
    expect(found?.status).toBe("cancelled");
  });
});

